// src/node/config.ts
async function bundleCode(fileName, logLevel) {
  const options = {
    entryPoints: [fileName],
    bundle: true,
    write: false,
    // resolveExtensions: ['.ts', '.js', '.json'],
    minify: false,
    logLevel: logLevel === "warn" ? "warning" : logLevel,
    platform: "node",
    allowOverwrite: false,
    sourcemap: false,
    format: "esm",
    target: "esnext",
    // format: OutputFormat.ESM,
    // mainFields: ['module', 'main'],
    banner: {
      "js": "import { createRequire } from 'module'; const require = createRequire(import.meta.url);"
    }
  };
  const built = await esbuild.build(options);
  const bundledCode = built.outputFiles?.[0].text;
  if (!bundledCode) throw new Error("Failed to load code - " + fileName);
  return bundledCode;
}
async function loadConfigFromBundledFile(bundle, fileName) {
  const nodeModulesDir = findNearestNodeModules(path2.dirname(fileName));
  if (nodeModulesDir) {
    await fs3.promises.mkdir(path2.resolve(nodeModulesDir, ".teeny-temp/"), {
      recursive: true
    });
  }
  const hash = `timestamp-${Date.now()}-${Math.random().toString(16).slice(2)}`;
  const tempFileName = nodeModulesDir ? path2.resolve(
    nodeModulesDir,
    `.teeny-temp/${path2.basename(fileName)}.${hash}.mjs`
  ) : `${fileName}.${hash}.mjs`;
  await fs3.promises.writeFile(tempFileName, bundle);
  try {
    return (await import(pathToFileURL(tempFileName).href)).default;
  } finally {
    fs3.unlink(tempFileName, () => {
    });
  }
}
async function loadConfigFromFile(configRoot, configFile, logLevel, customLogger) {
  const start = performance.now();
  const getTime = () => `${(performance.now() - start).toFixed(2)}ms`;
  let resolvedPath;
  if (configFile) {
    resolvedPath = path2.resolve(configFile);
  } else {
    for (const filename of DEFAULT_CONFIG_FILES) {
      const filePath = path2.resolve(configRoot, filename);
      if (!fs3.existsSync(filePath)) continue;
      resolvedPath = filePath;
      break;
    }
  }
  if (!resolvedPath) {
    throw new Error("no config file found.");
  }
  const isESM = true;
  try {
    const bundled = await bundleCode(resolvedPath, logLevel);
    const userConfig = await loadConfigFromBundledFile(
      bundled,
      resolvedPath
    );
    debug?.(`bundled config file loaded in ${getTime()}`);
    const config = await (typeof userConfig === "function" ? userConfig() : userConfig);
    if (!isObject(config)) {
      throw new Error(`config must export or return an object.`);
    }
    return {
      path: normalizePath(resolvedPath),
      config
      // dependencies: bundled.dependencies,
    };
  } catch (e) {
    createLogger(logLevel, { customLogger }).error(
      colors2.red(`failed to load config from ${resolvedPath}`),
      { error: e }
    );
    throw e;
  }
}
async function loadWranglerConfigFromFile(configRoot, configFile, logLevel, customLogger) {
  const start = performance.now();
  const getTime = () => `${(performance.now() - start).toFixed(2)}ms`;
  let resolvedPath;
  if (configFile) {
    resolvedPath = path2.resolve(configFile);
  } else {
    for (const filename of DEFAULT_WRANGLER_CONFIG_FILES) {
      const filePath = path2.resolve(configRoot, filename);
      if (!fs3.existsSync(filePath)) continue;
      resolvedPath = filePath;
      break;
    }
  }
  if (!resolvedPath) {
    throw new Error("no wrangler config file found.");
  }
  try {
    let loadedConfig = {};
    if (resolvedPath.endsWith(".json")) {
      loadedConfig = parseJSONC(readFileSync3(resolvedPath), resolvedPath);
    } else if (resolvedPath.endsWith(".toml")) {
      loadedConfig = parseTOML(readFileSync3(resolvedPath), resolvedPath);
    }
    return {
      path: normalizePath(resolvedPath),
      config: loadedConfig
    };
  } catch (e) {
    createLogger(logLevel, { customLogger }).error(
      colors2.red(`failed to load config from ${resolvedPath}`),
      { error: e }
    );
    throw e;
  }
}

