// src/node/wrangler/export.ts
import fs4 from "node:fs/promises";
import path3 from "node:path";
import { Miniflare } from "miniflare";
function getDatabaseInfoFromConfig(config, name) {
  for (const d1Database of config.d1_databases) {
    if (d1Database.database_id && (name === d1Database.database_name || name === d1Database.binding)) {
      return {
        uuid: d1Database.database_id,
        previewDatabaseUuid: d1Database.preview_database_id,
        binding: d1Database.binding,
        name: d1Database.database_name
        // migrationsTableName:
        //     d1Database.migrations_table,
        // migrationsFolderPath:
        //     d1Database.migrations_dir,
        // internal_env: d1Database.database_internal_env,
      };
    }
  }
  return null;
}
async function exportLocal(config, name, output, tables, noSchema, noData, persistencePath, logger) {
  const localDB = getDatabaseInfoFromConfig(config, name);
  if (!localDB) {
    throw new UserError(
      `Couldn't find a D1 DB with the name or binding '${name}' in wrangler.toml.`
    );
  }
  const id = localDB.previewDatabaseUuid ?? localDB.uuid;
  const d1Persist = path3.join(persistencePath, "v3", "d1");
  logger.info(
    `\u{1F300} Exporting local database ${name} (${id}) from ${readableRelative(
      d1Persist
    )}:`
  );
  const mf = new Miniflare({
    modules: true,
    script: "export default {}",
    d1Persist,
    d1Databases: { DATABASE: id }
  });
  const db = await mf.getD1Database("DATABASE");
  logger.info(`\u{1F300} Exporting SQL to ${output}...`);
  try {
    const dump = await db.prepare(`PRAGMA miniflare_d1_export(?,?,?);`).bind(noSchema, noData, ...tables).raw();
    await fs4.writeFile(output, dump[0].join("\n"));
  } catch (e) {
    throw new UserError(e.message);
  } finally {
    await mf.dispose();
  }
  logger.info(`Done!`);
}

